using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- Options with a default resolver (handles any type) ---
var webOptions = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() – returns JsonTypeInfo<Person> directly
JsonTypeInfo<Person> personInfo = webOptions.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person>  →  Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"  Serialized: {json}");

// 2) TryGetTypeInfo<T>() – succeeds for Person
if (webOptions.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? probed))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded  →  Type = {probed!.Type.Name}");
}

// --- Options locked to a source-gen context (only knows about Person) ---
var restricted = new JsonSerializerOptions { TypeInfoResolver = DemoContext.Default };

// Probe for a type the context DOES know about
if (restricted.TryGetTypeInfo<Person>(out var found))
{
    Console.WriteLine($"\nRestricted: TryGetTypeInfo<Person> succeeded  →  {found!.Type.Name}");
}

// Probe for a type the context does NOT know about – no exception
if (restricted.TryGetTypeInfo<int[]>(out _))
{
    Console.WriteLine("Restricted: TryGetTypeInfo<int[]> succeeded (unexpected)");
}
else
{
    Console.WriteLine("Restricted: TryGetTypeInfo<int[]> returned false – metadata not available");
}

// --- Types & source-gen context ---
public record Person(string Name, int Age);

[JsonSourceGenerationOptions(WriteIndented = false)]
[JsonSerializable(typeof(Person))]
internal partial class DemoContext : JsonSerializerContext;

